import { useState } from "react";

const WINNING_LINES = [
  [[0, 0], [0, 1], [0, 2]],
  [[1, 0], [1, 1], [1, 2]],
  [[2, 0], [2, 1], [2, 2]],
  [[0, 0], [1, 0], [2, 0]],
  [[0, 1], [1, 1], [2, 1]],
  [[0, 2], [1, 2], [2, 2]],
  [[0, 0], [1, 1], [2, 2]],
  [[0, 2], [1, 1], [2, 0]],
];

function winner(board) {
  for (const [a, b, c] of WINNING_LINES) {
    const player = board[a[0]][a[1]];

    if (
      player !== null &&
      player === board[b[0]][b[1]] &&
      player === board[c[0]][c[1]]
    ) {
      return player;
    }
  }

  return null;
}

function symbol(player) {
  return player === 0 ? "X" : "O";
}

export default function TicTacToe() {
  const [board, setBoard] = useState([
    [null, null, null],
    [null, null, null],
    [null, null, null],
  ]);

  const [turn, setTurn] = useState(0);

  const winningPlayer = winner(board);

  function play(row, col) {
    if (board[row][col] !== null || winningPlayer !== null) return;

    const nextBoard = board.map(row => [...row]);
    nextBoard[row][col] = turn;

    setBoard(nextBoard);
    setTurn(1 - turn);
  }

  function reset() {
    setBoard([
      [null, null, null],
      [null, null, null],
      [null, null, null],
    ]);

    setTurn(0);
  }

  return (
    <main>
      <h1>Tic Tac Toe</h1>

      <p>
        {winningPlayer !== null
          ? `${symbol(winningPlayer)} wins!`
          : `Turn: ${symbol(turn)}`}
      </p>

      <table style={{ fontFamily: "monospace" }}>
        <tbody>
          {board.map((row, r) => (
            <tr key={r}>
              {row.map((cell, c) => (
                <td
                  key={c}
                  onClick={() => play(r, c)}
                  style={{ border: "1px solid", cursor: "pointer" }}
                >
                  {cell === null ? "\u00A0" : symbol(cell)}
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>

      <p>
        <button onClick={reset}>Play Again</button>
      </p>
    </main>
  );
}
